    public void handleOrder(Client client, Object message)
    {
        // not snapshot, only updates
        // {
        //   "channel": "account_order_updates",
        //   "data": [
        //     {
        //       "i": 1559665358,
        //       "I": null,
        //       "u": "BrZp5bidJ3WUvceSq7X78bhjTfZXeezzGvGEV4hAYKTa",
        //       "s": "BTC",
        //       "d": "bid",
        //       "p": "89501",
        //       "ip": "89501",
        //       "lp": "89501",
        //       "a": "0.00012",
        //       "f": "0.00012",
        //       "oe": "fulfill_limit",
        //       "os": "filled",
        //       "ot": "limit",
        //       "sp": null,
        //       "si": null,
        //       "r": false,
        //       "ct": 1765017049008,
        //       "ut": 1765017219639,
        //       "li": 1559696133
        //     }
        //   ]
        // }
        Object data = this.safeList(message, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        if (Helpers.isTrue(Helpers.isEqual(this.orders, null)))
        {
            Object limit = this.safeInteger(this.options, "ordersLimit", 1000);
            this.orders = new ArrayCache.ArrayCacheBySymbolById(((Number)limit).intValue());
        }
        Object dataLength = Helpers.getArrayLength(data);
        if (Helpers.isTrue(Helpers.isEqual(dataLength, 0)))
        {
            return;
        }
        Object stored = this.orders;
        Object messageHash = "order";
        Object marketSymbols = new java.util.HashMap<String, Object>() {{}};
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(data)); i++)
        {
            Object rawOrder = Helpers.GetValue(data, i);
            Object order = this.parseOrder(rawOrder);
            Helpers.callDynamically(stored, "append", new Object[]{order});
            Object symbol = this.safeString(order, "symbol");
            Helpers.addElementToObject(marketSymbols, symbol, true);
        }
        Object keys = Helpers.objectKeys(marketSymbols);
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(keys)); i++)
        {
            Object symbol = Helpers.GetValue(keys, i);
            Object innerMessageHash = Helpers.add(Helpers.add(messageHash, ":"), symbol);
            client.resolve(stored, innerMessageHash);
        }
        client.resolve(stored, messageHash);
    }

    public Object handleErrorMessage(Client client, Object message)
    {
        //
        // 'rl' key is present only when a rate-limited API key is used
        // {"id":"64107e37-a999-4b90-a3cf-b4322ae110d9","type":"cancel_order","code":420,"err":"Failed to cancel order","t":1769474703073,"rl":{"r":1245,"q":1250,"t":56}}
        //
        Object error = this.safeString(message, "err", "");
        Object postType = this.safeString(message, "type", "");
        Object data = this.safeDict(message, "data", new java.util.HashMap<String, Object>() {{}});
        Object id = this.safeString(message, "id");
        if (Helpers.isTrue(Helpers.isEqual(id, null)))
        {
            id = this.safeString(data, "id");
        }
        try
        {
            this.handleErrors(0, error, "", postType, Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(this.options, "ws"), "options"), "headers"), this.json(data), message, new java.util.HashMap<String, Object>() {{}}, new java.util.HashMap<String, Object>() {{}});
        } catch(Exception e)
        {
            client.reject(e, id);
            return true;
        }
        return false;
    }

